import { FastifyRequest, FastifyReply } from 'fastify';
import { ILeaveBalanceService } from './balance.service';
import { z } from 'zod';

interface AuthenticatedRequest extends FastifyRequest {
  user: {
    id: string;
    role: 'employee' | 'manager' | 'admin';
  };
}

const initializeSchema = z.object({
  employeeId: z.string().uuid(),
  policyId: z.string().uuid(),
  fiscalYear: z.number().int().min(2000).max(2100)
});

const deductRestoreSchema = z.object({
  employeeId: z.string().uuid(),
  policyId: z.string().uuid(),
  days: z.number().positive()
});

export class BalanceController {
  constructor(private readonly balanceService: ILeaveBalanceService) {}

  async getBalance(req: AuthenticatedRequest, reply: FastifyReply) {
    const { employeeId, policyId } = req.params as { employeeId: string; policyId: string };
    const balance = await this.balanceService.getBalance(employeeId, policyId);
    if (!balance) return reply.status(404).send({ error: 'Balance not found' });
    return reply.send(balance);
  }

  async getBalancesByEmployee(req: AuthenticatedRequest, reply: FastifyReply) {
    const { employeeId } = req.params as { employeeId: string };
    const balances = await this.balanceService.getBalancesByEmployee(employeeId);
    return reply.send(balances);
  }

  async initializeBalance(req: AuthenticatedRequest, reply: FastifyReply) {
    const parsed = initializeSchema.safeParse(req.body);
    if (!parsed.success) return reply.status(400).send({ error: parsed.error.issues });
    const { employeeId, policyId, fiscalYear } = parsed.data;
    const balance = await this.balanceService.initializeBalance(employeeId, policyId, fiscalYear);
    return reply.status(201).send(balance);
  }

  async deductBalance(req: AuthenticatedRequest, reply: FastifyReply) {
    const parsed = deductRestoreSchema.safeParse(req.body);
    if (!parsed.success) return reply.status(400).send({ error: parsed.error.issues });
    const { employeeId, policyId, days } = parsed.data;
    const balance = await this.balanceService.deductBalance(employeeId, policyId, days);
    return reply.send(balance);
  }

  async restoreBalance(req: AuthenticatedRequest, reply: FastifyReply) {
    const parsed = deductRestoreSchema.safeParse(req.body);
    if (!parsed.success) return reply.status(400).send({ error: parsed.error.issues });
    const { employeeId, policyId, days } = parsed.data;
    const balance = await this.balanceService.restoreBalance(employeeId, policyId, days);
    return reply.send(balance);
  }
